export function integrationContractFor(capabilityKey) {
  return axiomIntegrationContracts.find((item) => item.capability === capabilityKey) || null;
}

export function requiredIntegrationHooks(capabilityKey) {
  const contract = integrationContractFor(capabilityKey);
  if (!contract) return [];

  return Object.values(contract.manualHooks).filter(Boolean);
}

export function validateIntegrationHooks(capabilityKey, hooks = {}) {
  const required = requiredIntegrationHooks(capabilityKey)
    .filter((hook) => !hook.startsWith("bind "))
    .map((hook) => hook.replace(/ .+$/, ""));
  const missing = required.filter((hook) => typeof hooks[hook] !== "function");
  return {
    ok: missing.length === 0,
    capability: capabilityKey,
    required,
    missing,
    contract: integrationContractFor(capabilityKey),
  };
}
